#include<bits/stdc++.h>
using namespace std;
const int N=3e6+10;
int t[N][150],idx,cnt[N];
void add(string s){
	int p=0;
	for(int i=0;i<s.size();i++){
		if(!t[p][s[i]])t[p][s[i]]=++idx;
		p=t[p][s[i]];
		cnt[p]++;
	}
}
int find(string s){
	int p=0;
	for(int i=0;i<s.size();i++){
		if(!t[p][s[i]])return 0;
		p=t[p][s[i]];
	}
	return cnt[p];
}
int main()
{
	int T;
	cin>>T;
	while(T--){
		int n,q;
		cin>>n>>q;
		for(int j=0;j<idx;j++){
			cnt[j]=0;
			for(int i=0;i<150;i++)t[j][i]=0;
		}
		idx=0;
		for(int i=0;i<n;i++){
			string s;
			cin>>s;
			add(s);
		}
		for(int i=0;i<q;i++){
			string s;
			cin>>s;
			cout<<find(s)<<endl;
		}
	}
}
